%% MPM-CoEA Visualization Script (Corrected)
% Matches the actual files generated by mpmcoea_solver.hpp
clear; clc; close all;

%% Set Paths
viz_dir = 'E:\HITSZ\Research\Multimodal_Multiparty_Optimization\ThesisProject\Visualization';
solutions_dir = fullfile(viz_dir, 'solutions');

%% Load Landscape Files
fprintf('Loading landscape files...\n');

% Load DM0 conditional landscape (x1 varies, x2 fixed)
dm0_file = fullfile(viz_dir, 'landscape_dm0_conditional.txt');
if exist(dm0_file, 'file')
    dm0_data = readmatrix(dm0_file);
    fprintf('  ✓ Loaded DM0 landscape: %d points\n', size(dm0_data, 1));
else
    warning('DM0 landscape file not found: %s', dm0_file);
    dm0_data = [];
end

% Load DM1 conditional landscape (x2 varies, x1 fixed)
dm1_file = fullfile(viz_dir, 'landscape_dm1_conditional.txt');
if exist(dm1_file, 'file')
    dm1_data = readmatrix(dm1_file);
    fprintf('  ✓ Loaded DM1 landscape: %d points\n', size(dm1_data, 1));
else
    warning('DM1 landscape file not found: %s', dm1_file);
    dm1_data = [];
end

% Load global grid landscape
global_file = fullfile(viz_dir, 'landscape_global_grid.txt');
if exist(global_file, 'file')
    global_data = readmatrix(global_file);
    fprintf('  ✓ Loaded global landscape: %d points\n', size(global_data, 1));
else
    warning('Global landscape file not found: %s', global_file);
    global_data = [];
end

%% Load Solution Files
fprintf('Loading solution files...\n');
sol_files = dir(fullfile(solutions_dir, 'gen_*.txt'));
num_gen_files = length(sol_files);

if num_gen_files > 0
    % Sort files by generation number
    gen_nums = zeros(num_gen_files, 1);
    for i = 1:num_gen_files
        fname = sol_files(i).name;
        tokens = regexp(fname, 'gen_(\d+)_', 'tokens');
        if ~isempty(tokens)
            gen_nums(i) = str2double(tokens{1}{1});
        end
    end
    [gen_nums, sort_idx] = sort(gen_nums);
    sol_files = sol_files(sort_idx);
    fprintf('  ✓ Loaded %d generation files\n', num_gen_files);
else
    warning('No solution files found in %s', solutions_dir);
end

%% Create Main Figure
figure('Position', [100, 100, 1800, 1200], 'Color', 'white');
sgtitle('MPM-CoEA: Multi-Party Multi-Modal Optimization Visualization', ...
    'FontSize', 16, 'FontWeight', 'bold');

%% Subplot 1: DM0's Conditional Landscape (Senior's Point #1)
subplot(2, 3, 1);
if ~isempty(dm0_data)
    plot(dm0_data(:,1), dm0_data(:,2), 'b-', 'LineWidth', 2);
    hold on;
    % Mark best point for DM0
    [max_fit, max_idx] = max(dm0_data(:,2));
    plot(dm0_data(max_idx,1), dm0_data(max_idx,2), 'r*', ...
        'MarkerSize', 15, 'LineWidth', 2, 'DisplayName', 'Best for DM0');
    hold off;
    grid on;
    xlabel('x_1 (DM0''s variable)', 'FontSize', 12);
    ylabel('Fitness', 'FontSize', 12);
    title('DM0''s Fitness Landscape (x_2 fixed)', 'FontSize', 14, 'FontWeight', 'bold');
    legend('Location', 'best');
else
    text(0.5, 0.5, 'No DM0 Data', 'HorizontalAlignment', 'center');
end

%% Subplot 2: DM1's Conditional Landscape (Senior's Point #1)
subplot(2, 3, 2);
if ~isempty(dm1_data)
    plot(dm1_data(:,1), dm1_data(:,2), 'm-', 'LineWidth', 2);
    hold on;
    % Mark best point for DM1
    [max_fit, max_idx] = max(dm1_data(:,2));
    plot(dm1_data(max_idx,1), dm1_data(max_idx,2), 'y*', ...
        'MarkerSize', 15, 'LineWidth', 2, 'DisplayName', 'Best for DM1');
    hold off;
    grid on;
    xlabel('x_2 (DM1''s variable)', 'FontSize', 12);
    ylabel('Fitness', 'FontSize', 12);
    title('DM1''s Fitness Landscape (x_1 fixed)', 'FontSize', 14, 'FontWeight', 'bold');
    legend('Location', 'best');
else
    text(0.5, 0.5, 'No DM1 Data', 'HorizontalAlignment', 'center');
end

%% Subplot 3: Global 2D Landscape (Contour)
subplot(2, 3, 3);
if ~isempty(global_data)
    % Reshape for contour plot
    x1_unique = unique(global_data(:,1));
    x2_unique = unique(global_data(:,2));
    resolution = length(x1_unique);
    
    X1 = reshape(global_data(:,1), resolution, resolution);
    X2 = reshape(global_data(:,2), resolution, resolution);
    F = reshape(global_data(:,3), resolution, resolution);
    
    contourf(X1, X2, F, 50, 'LineColor', 'none');
    colorbar;
    hold on;
    
    % Mark global optimum
    [max_fit, max_idx] = max(F(:));
    [opt_x1, opt_x2] = ind2sub(size(F), max_idx);
    plot(X1(opt_x1, opt_x2), X2(opt_x1, opt_x2), 'r*', ...
        'MarkerSize', 20, 'LineWidth', 3, 'DisplayName', 'Global Optimum');
    
    hold off;
    axis equal;
    xlabel('x_1', 'FontSize', 12);
    ylabel('x_2', 'FontSize', 12);
    title('Global Fitness Landscape', 'FontSize', 14, 'FontWeight', 'bold');
else
    text(0.5, 0.5, 'No Global Data', 'HorizontalAlignment', 'center');
end

%% Subplot 4: Initial Population Distribution
subplot(2, 3, 4);
if num_gen_files > 0
    % Load first generation
    first_gen_file = fullfile(solutions_dir, sol_files(1).name);
    first_gen_data = readmatrix(first_gen_file);
    
    scatter(first_gen_data(:,1), first_gen_data(:,2), 40, ...
        first_gen_data(:,3), 'filled', 'MarkerEdgeColor', 'k');
    colorbar;
    hold on;
    
    if ~isempty(global_data)
        plot(X1(opt_x1, opt_x2), X2(opt_x1, opt_x2), 'r*', ...
            'MarkerSize', 20, 'LineWidth', 3, 'DisplayName', 'Global Optimum');
    end
    
    hold off;
    axis equal;
    xlim([0 1]);
    ylim([0 1]);
    grid on;
    xlabel('x_1', 'FontSize', 12);
    ylabel('x_2', 'FontSize', 12);
    title(sprintf('Initial Population (Gen %d)', gen_nums(1)), ...
        'FontSize', 14, 'FontWeight', 'bold');
    legend('Location', 'best');
else
    text(0.5, 0.5, 'No Solution Data', 'HorizontalAlignment', 'center');
end

%% Subplot 5: Final Population Distribution
subplot(2, 3, 5);
if num_gen_files > 0
    % Load last generation
    last_gen_file = fullfile(solutions_dir, sol_files(end).name);
    last_gen_data = readmatrix(last_gen_file);
    
    scatter(last_gen_data(:,1), last_gen_data(:,2), 40, ...
        last_gen_data(:,3), 'filled', 'MarkerEdgeColor', 'k');
    colorbar;
    hold on;
    
    if ~isempty(global_data)
        plot(X1(opt_x1, opt_x2), X2(opt_x1, opt_x2), 'r*', ...
            'MarkerSize', 20, 'LineWidth', 3, 'DisplayName', 'Global Optimum');
    end
    
    hold off;
    axis equal;
    xlim([0 1]);
    ylim([0 1]);
    grid on;
    xlabel('x_1', 'FontSize', 12);
    ylabel('x_2', 'FontSize', 12);
    title(sprintf('Final Population (Gen %d)', gen_nums(end)), ...
        'FontSize', 14, 'FontWeight', 'bold');
    legend('Location', 'best');
else
    text(0.5, 0.5, 'No Solution Data', 'HorizontalAlignment', 'center');
end

%% Subplot 6: Convergence Curve
subplot(2, 3, 6);
if num_gen_files > 0
    best_fitness = zeros(num_gen_files, 1);
    for i = 1:num_gen_files
        gen_file = fullfile(solutions_dir, sol_files(i).name);
        gen_data = readmatrix(gen_file);
        best_fitness(i) = max(gen_data(:,3));
    end
    
    plot(gen_nums, best_fitness, 'b-o', 'LineWidth', 2, ...
        'MarkerSize', 6, 'MarkerFaceColor', 'b');
    hold on;
    
    if ~isempty(global_data)
        yline(max(global_data(:,3)), 'r--', 'LineWidth', 2, ...
            'DisplayName', 'Global Optimum');
    end
    
    xlabel('Generation', 'FontSize', 12);
    ylabel('Best Fitness', 'FontSize', 12);
    title('Convergence Curve', 'FontSize', 14, 'FontWeight', 'bold');
    grid on;
    legend('Location', 'southeast');
    hold off;
else
    text(0.5, 0.5, 'No Convergence Data', 'HorizontalAlignment', 'center');
end

%% Save Figure
save_path = fullfile(viz_dir, 'mpmmo_complete_visualization.png');
saveas(gcf, save_path);
fprintf('\n✓ Visualization saved to: %s\n', save_path);

%% Print Summary
fprintf('\n=== Visualization Summary ===\n');
fprintf('DM0 Landscape: %s\n', dm0_file);
fprintf('DM1 Landscape: %s\n', dm1_file);
fprintf('Global Landscape: %s\n', global_file);
fprintf('Solution Files: %d generations\n', num_gen_files);
if num_gen_files > 0
    fprintf('Generation Range: %d to %d\n', gen_nums(1), gen_nums(end));
end
fprintf('\nCheck the figure window for detailed visualization.\n');